class Solution:
    def calculate(self, s: str) -> int:
        stack = []
        curr_num = 0
        operation = '+'
        s = s + '+'
        for char in s:
            if char.isdigit():
                curr_num = curr_num * 10 + int(char)
            elif char in ['+', '-', '*', '/']:
                if operation == '+':
                    stack.append(curr_num)
                elif operation == '-':
                    stack.append(-curr_num)
                elif operation == '*':
                    stack.append(stack.pop() * curr_num)
                elif operation == '/':
                    stack.append(int(stack.pop() / curr_num))
                operation = char
                curr_num = 0
            elif char == ' ':
                continue
        return sum(stack)

